function calcBreakeven(params){
  const {users, cacheMB, energyPerHit, savedMsPerHit, valuePerMs, pricePerMB} = params;
  const energyCost = energyPerHit * users;
  const dataValue = savedMsPerHit * users * valuePerMs;
  const breakevenMonths = (cacheMB * pricePerMB) / ((dataValue) - energyCost);
  return breakevenMonths;
}
```

