function needsRefresh(lastRefresh, ttlHours) {
  const now = Date.now();
  const ttlMs = ttlHours * 60 * 60 * 1000;
  return (now - lastRefresh) >= ttlMs;
}

function getRefreshStrategy(device) {
  const batteryLevel = device.battery ?? 100;
  const isCharging = device.isCharging ?? false;

  if (batteryLevel < 20 && !isCharging) {
    return 'defer';
  } else if (batteryLevel < 50) {
    return 'adaptive';
  }
  return 'standard';
}
```

## Why This Is Asked

This question tests understanding of edge compute architecture, privacy-preserving data transfer, and cross-region cost modeling. It forces candidates to make trade-offs between latency, bandwidth, and regulatory compliance while demonstrating practical planning skills.

## Key Concepts

- **Edge locality and regional caching**: Evaluating feature flags at the CDN edge minimizes round-trip time to origin servers
- **Privacy-preserving deltas**: Shipping only anonymized changes rather than full state reduces bandwidth and exposure risk
- **Data residency and encryption**: Compliance with GDPR, CCPA, and regional data sovereignty requirements adds infrastructure cost
- **Phased rollout**: Gradual deployment with canary releases reduces risk across regions
- **Drift detection and rollback**: Monitoring for configuration drift and automated rollback procedures ensure reliability
- **Break-even analysis**: Quantifying backend load reduction, latency gains, and operational savings against implementation costs

## Code Example

```javascript
// Minimal CBA data model sketch
class RegionCost {
  constructor(region, cacheKB, latencyMs, deltaKB) {
    this.region = region;
    this.cacheKB = cacheKB;
    this.latencyMs = latencyMs;
    this.deltaKB = deltaKB;
  }

  monthlyBandwidth(deltaKB, requestsPerMonth) {
    return (deltaKB * requestsPerMonth) / 1024; // MB/month
  }

  annualCost(monthlyBandwidthMB, complianceTier) {
    const bandwidthCost = monthlyBandwidthMB * 12 * 0.05; // $0.05/MB
    const complianceCost = complianceTier * 5000; // $5k-$15k/region
    return bandwidthCost + complianceCost;
  }
}

const regions = [
  new RegionCost('us-east', 32, 1.2, 0.5),
  new RegionCost('eu-west', 24, 1.8, 0.4),
  new RegionCost('ap-south', 16, 2.5, 0.3)
];
```

