```javascript
class OnDeviceRankingEngine {
  constructor(config) {
    this.model = null;
    this.dpTracker = new DpBudgetTracker({
      quarterlyBudgets: [0.6, 0.4, 0.5, 0.5],
      deltaBudget: 1e-6
    });
    this.lastSync = 0;
  }

  async infer(sessionContext) {
    const features = this.extractFeatures(sessionContext);
    const rankings = this.model.predict(features);

    this.scheduleDpDelta();
    return rankings;
  }

  async scheduleDpDelta() {
    const elapsed = Date.now() - this.lastSync;
    if (elapsed >= 6 * 60 * 60 * 1000) { // 6 hours
      await this.transmitDpDelta();
      this.lastSync = Date.now();
    }
  }

  async transmitDpDelta() {
    const localStats = this.model.collectSufficientStatistics();
    const { epsilon, delta } = this.dpTracker.quarterlyAllocation();

    const clipped = this.clipByNorm(localStats, 1.0);
    const noise = this.addGaussianNoise(clipped, epsilon, delta);

    const encrypted = await this.sealEncrypt({
      delta: noise,
      deviceId: this.getDeviceId(),
      timestamp: Date.now()
    });

    await this.telemetryChannel.send(encrypted); // 12 bytes
    this.dpTracker.spend(epsilon, delta, 1);
  }

  clipByNorm(stats, maxNorm) {
    const norm = Math.sqrt(stats.reduce((s, v) => s + v*v, 0));
    if (norm <= maxNorm) return stats;
    return stats.map(v => v * maxNorm / norm);
  }

  addGaussianNoise(stats, epsilon, delta) {
    const sigma = Math.sqrt(2 * Math.log(1.25/delta)) / epsilon;
    return stats.map(v => v + this.gaussianRandom() * sigma);
  }

  async sealEncrypt(payload) {
    const key = await this.getSessionKey();
    const sealed = await crypto.subtle.encrypt(
      { name: 'AES-GCM', iv: crypto.getRandomValues(new Uint8Array(12)) },
      key,
      new TextEncoder().encode(JSON.stringify(payload))
    );
    return new Uint8Array(sealed);
  }
}
```

