    this.cache = new Map();
  }

  async shouldPrefetch(deviceState) {
    const { batteryLevel, networkType, isCharging } = deviceState;
    return (
      batteryLevel > this.config.batteryThreshold &&
      (networkType === 'wifi' || isCharging)
    );
  }

  async prefetch(assets) {
    if (!(await this.shouldPrefetch(getDeviceState()))) return;
    for (const asset of assets) {
      const cached = await caches.match(asset.url);
      if (!cached) {
        const response = await fetch(asset.url);
        await caches.put(asset.url, response.clone());
      }
    }
  }

  async getAsset(url) {
    const cached = await caches.match(url);
    if (cached) return cached;
    return this.handleMiss(url);
  }

  async handleMiss(url) {
    return fetch(url).catch(() => getOfflineFallback(url));
  }
}
