// Implementation sketch: simple local search index
class LocalIndex {
  constructor() { this.docs = []; }
  build(docs) { this.docs = docs.map(d => ({ id: d.id, text: d.content })); }
  search(q) {
    const terms = q.toLowerCase().split(/\s+/);
    return this.docs.filter(d => terms.every(t => d.text.toLowerCase().includes(t)));
  }
  deltaUpdate(changes) {
    // apply lightweight patches to docs
    changes.forEach(c => {
      const idx = this.docs.findIndex(d => d.id === c.id);
      if (idx >= 0) this.docs[idx] = { ...this.docs[idx], ...c.patch };
      else this.docs.push({ id: c.id, text: c.patch.content });
    });
  }
}
```

