// CBA calculation framework for on-device voice assistant
function calculateCBA(months, implementationCost, operationalCost, userValue, complianceCost) {
  const totalCost = implementationCost + (operationalCost * months) + (complianceCost * months);
  const totalRevenue = userValue * months;
  return {
    netValue: totalRevenue - totalCost,
    breakEvenMonth: Math.ceil(implementationCost / (userValue - operationalCost - complianceCost)),
    roi: ((totalRevenue - totalCost) / totalCost) * 100
  };
}
```

